    15→*/
    16→
    17→// Package rbac implements the authorizer.Authorizer interface using roles base access control.
    18→package rbac
    19→
    20→import (
    21→	"context"
    22→
    23→	rbacv1 "k8s.io/api/rbac/v1"
    24→	utilerrors "k8s.io/apimachinery/pkg/util/errors"
    25→	"k8s.io/apiserver/pkg/authentication/user"
    26→	"k8s.io/apiserver/pkg/authorization/authorizer"
    27→	rbacregistryvalidation "k8s.io/kubernetes/pkg/registry/rbac/validation"
    28→)
    29→
    30→type RoleToRuleMapper interface {
    31→	// GetRoleReferenceRules attempts to resolve the role reference of a RoleBinding or ClusterRoleBinding.  The passed namespace should be the namespace
    32→	// of the role binding, the empty string if a cluster role binding.
    33→	GetRoleReferenceRules(ctx context.Context, roleRef rbacv1.RoleRef, namespace string) ([]rbacv1.PolicyRule, error)
    34→}
    35→
    36→type SubjectLocator interface {
    37→	AllowedSubjects(ctx context.Context, attributes authorizer.Attributes) ([]rbacv1.Subject, error)
    38→}
    39→
    40→var _ = SubjectLocator(&SubjectAccessEvaluator{})
    41→
    42→type SubjectAccessEvaluator struct {
    43→	superUser string
    44→
    45→	roleBindingLister        rbacregistryvalidation.RoleBindingLister
    46→	clusterRoleBindingLister rbacregistryvalidation.ClusterRoleBindingLister
    47→	roleToRuleMapper         RoleToRuleMapper
    48→}
    49→
    50→func NewSubjectAccessEvaluator(roles rbacregistryvalidation.RoleGetter, roleBindings rbacregistryvalidation.RoleBindingLister, clusterRoles rbacregistryvalidation.ClusterRoleGetter, clusterRoleBindings rbacregistryvalidation.ClusterRoleBindingLister, superUser string) *SubjectAccessEvaluator {
    51→	subjectLocator := &SubjectAccessEvaluator{
    52→		superUser:                superUser,
    53→		roleBindingLister:        roleBindings,
    54→		clusterRoleBindingLister: clusterRoleBindings,
    55→		roleToRuleMapper: rbacregistryvalidation.NewDefaultRuleResolver(
    56→			roles, roleBindings, clusterRoles, clusterRoleBindings,
    57→		),
    58→	}
    59→	return subjectLocator
    60→}
    61→
    62→// AllowedSubjects returns the subjects that can perform an action and any errors encountered while computing the list.
    63→// It is possible to have both subjects and errors returned if some rolebindings couldn't be resolved, but others could be.
    64→func (r *SubjectAccessEvaluator) AllowedSubjects(ctx context.Context, requestAttributes authorizer.Attributes) ([]rbacv1.Subject, error) {
    65→	subjects := []rbacv1.Subject{{Kind: rbacv1.GroupKind, APIGroup: rbacv1.GroupName, Name: user.SystemPrivilegedGroup}}
    66→	if len(r.superUser) > 0 {
    67→		subjects = append(subjects, rbacv1.Subject{Kind: rbacv1.UserKind, APIGroup: rbacv1.GroupName, Name: r.superUser})
    68→	}
    69→	errorlist := []error{}
    70→
    71→	if clusterRoleBindings, err := r.clusterRoleBindingLister.ListClusterRoleBindings(ctx); err != nil {
    72→		errorlist = append(errorlist, err)
    73→
    74→	} else {
    75→		for _, clusterRoleBinding := range clusterRoleBindings {
    76→			rules, err := r.roleToRuleMapper.GetRoleReferenceRules(ctx, clusterRoleBinding.RoleRef, "")
    77→			if err != nil {
    78→				// if we have an error, just keep track of it and keep processing.  Since rules are additive,
    79→				// missing a reference is bad, but we can continue with other rolebindings and still have a list
    80→				// that does not contain any invalid values
    81→				errorlist = append(errorlist, err)
    82→			}
    83→			if RulesAllow(requestAttributes, rules...) {
    84→				subjects = append(subjects, clusterRoleBinding.Subjects...)
    85→			}
    86→		}
    87→	}
    88→
    89→	if namespace := requestAttributes.GetNamespace(); len(namespace) > 0 {
    90→		if roleBindings, err := r.roleBindingLister.ListRoleBindings(ctx, namespace); err != nil {
    91→			errorlist = append(errorlist, err)
    92→
    93→		} else {
    94→			for _, roleBinding := range roleBindings {
    95→				rules, err := r.roleToRuleMapper.GetRoleReferenceRules(ctx, roleBinding.RoleRef, namespace)
    96→				if err != nil {
    97→					// if we have an error, just keep track of it and keep processing.  Since rules are additive,
    98→					// missing a reference is bad, but we can continue with other rolebindings and still have a list
    99→					// that does not contain any invalid values
   100→					errorlist = append(errorlist, err)
   101→				}
   102→				if RulesAllow(requestAttributes, rules...) {
   103→					subjects = append(subjects, roleBinding.Subjects...)
   104→				}
   105→			}
   106→		}
   107→	}
   108→
   109→	dedupedSubjects := []rbacv1.Subject{}
   110→	for _, subject := range subjects {
   111→		found := false
   112→		for _, curr := range dedupedSubjects {
   113→			if curr == subject {
   114→				found = true
   115→				break
   116→			}
   117→		}
   118→
   119→		if !found {
   120→			dedupedSubjects = append(dedupedSubjects, subject)
   121→		}
   122→	}
   123→
   124→	return subjects, utilerrors.NewAggregate(errorlist)
   125→}
